// Bitmask — values may be combined with |.
type FORMAT_MESSAGE_OPTIONS uint32

const (
	FORMAT_MESSAGE_ALLOCATE_BUFFER FORMAT_MESSAGE_OPTIONS = 256
	FORMAT_MESSAGE_ARGUMENT_ARRAY  FORMAT_MESSAGE_OPTIONS = 8192
	FORMAT_MESSAGE_FROM_HMODULE    FORMAT_MESSAGE_OPTIONS = 2048
	FORMAT_MESSAGE_FROM_STRING     FORMAT_MESSAGE_OPTIONS = 1024
	FORMAT_MESSAGE_FROM_SYSTEM     FORMAT_MESSAGE_OPTIONS = 4096
	FORMAT_MESSAGE_IGNORE_INSERTS  FORMAT_MESSAGE_OPTIONS = 512
)

// String returns the FORMAT_MESSAGE_OPTIONS constant's name, or its numeric form when
// the value is not a known constant.
func (e FORMAT_MESSAGE_OPTIONS) String() string {
	var parts []string
	if e&FORMAT_MESSAGE_ALLOCATE_BUFFER != 0 {
		parts = append(parts, "FORMAT_MESSAGE_ALLOCATE_BUFFER")
	}
	if e&FORMAT_MESSAGE_ARGUMENT_ARRAY != 0 {
		parts = append(parts, "FORMAT_MESSAGE_ARGUMENT_ARRAY")
	}
	if e&FORMAT_MESSAGE_FROM_HMODULE != 0 {
		parts = append(parts, "FORMAT_MESSAGE_FROM_HMODULE")
	}
	if e&FORMAT_MESSAGE_FROM_STRING != 0 {
		parts = append(parts, "FORMAT_MESSAGE_FROM_STRING")
	}
	if e&FORMAT_MESSAGE_FROM_SYSTEM != 0 {
		parts = append(parts, "FORMAT_MESSAGE_FROM_SYSTEM")
	}
	if e&FORMAT_MESSAGE_IGNORE_INSERTS != 0 {
		parts = append(parts, "FORMAT_MESSAGE_IGNORE_INSERTS")
	}
	if len(parts) == 0 {
		return "0"
	}
	return strings.Join(parts, "|")
}

